formulas.expression:
IF(CONTAINS({!$Record.Website}, "gmail"),"",

LOWER(IF(AND(NOT(ISNULL({!$Record.Website})), NOT(ISBLANK({!$Record.Website}))), IF(FIND("www.", {!$Record.Website}) > 0 , SUBSTITUTE({!$Record.Website}, LEFT({!$Record.Website}, FIND(".", {!$Record.Website})), NULL), {!$Record.Website}), NULL))

)
